const accuracy = $('Get Daily Accuracy').first().json;
const price = $('Get Price').first().json;

const acc = accuracy.accuracy_pct ? Math.round(accuracy.accuracy_pct) : 'N/A';
const btcPrice = price.price ? Number(price.price).toLocaleString('en-US') : 'N/A';
const change24h = price.change_24h_pct ? price.change_24h_pct.toFixed(2) : 'N/A';

const byTf = accuracy.by_timeframe || {};
let tfBreakdown = '';
for (const [tf, data] of Object.entries(byTf)) {
  const tfAcc = data.accuracy_pct ? Math.round(data.accuracy_pct) : 'N/A';
  const emoji = tfAcc >= 70 ? '✅' : tfAcc >= 50 ? '🟡' : '❌';
  tfBreakdown += `${emoji} ${tf}: ${tfAcc}%\n`;
}

const resultEmoji = change24h > 0 ? '📈' : '📉';
const accEmoji = acc >= 70 ? '🏆' : acc >= 50 ? '📊' : '📉';

const date = new Date().toLocaleDateString('en-US', { timeZone: 'UTC', month: 'short', day: 'numeric', year: 'numeric' });

const html = `${accEmoji} <b>Daily Summary</b> — ${date}

${resultEmoji} <b>BTC:</b> $${btcPrice} (${change24h}% 24h)
✅ <b>Today's accuracy:</b> ${acc}%
${tfBreakdown ? `\n<b>By timeframe:</b>\n${tfBreakdown}` : ''}
<i>See you tomorrow! 🔮</i>`;

return [{ json: { message: html } }];
